import React from 'react';
import { NavLink } from 'react-router-dom';
import logo from '../assets/logo.svg'; // Use logo.svg (fallback)
// import logo from '../assets/logo.png'; // Uncomment if logo.png exists


const Sidebar = () => {
  return (
    <div className="sidebar">
      <img src={logo} alt="NeuroFleetX" className="h-8 mb-6" onError={(e) => {
        console.error('Failed to load logo:', e);
        e.target.src = 'https://via.placeholder.com/100x40?text=NeuroFleetX'; // Fallback image
      }} />
      <nav className="space-y-2">
        <NavLink
          to="/"
          className={({ isActive }) =>
            `no-underline text-white hover:bg-gray-700 p-2 rounded block ${isActive ? 'bg-gray-700' : ''}`
          }
        >
          Dashboard
        </NavLink>
        <NavLink
          to="/live-tracking"
          className={({ isActive }) =>
            `no-underline text-white hover:bg-gray-700 p-2 rounded block ${isActive ? 'bg-gray-700' : ''}`
          }
        >
          Live Tracking
        </NavLink>
        <NavLink
          to="/route-optimization"
          className={({ isActive }) =>
            `no-underline text-white hover:bg-gray-700 p-2 rounded block ${isActive ? 'bg-gray-700' : ''}`
          }
        >
          Route Optimization
        </NavLink>
        <NavLink
          to="/traffic-layer"
          className={({ isActive }) =>
            `no-underline text-white hover:bg-gray-700 p-2 rounded block ${isActive ? 'bg-gray-700' : ''}`
          }
        >
          Traffic Layer
        </NavLink>
        <NavLink
          to="/notifications"
          className={({ isActive }) =>
            `no-underline text-white hover:bg-gray-700 p-2 rounded block ${isActive ? 'bg-gray-700' : ''}`
          }
        >
          Notifications
        </NavLink>
      </nav>
    </div>
  );
};


export default Sidebar;
